/**
 * PREBUILD CONTENT MAP GENERATOR
 *
 * Runs automatically before `next build` and `next dev` (see package.json).
 * Scans content/ and writes import maps + metadata into src/generated/.
 * It NEVER modifies anything inside content/ — your MDX files are safe.
 *
 * Generated files (do not edit by hand):
 *   src/generated/manualProblems.ts  — map of content/manual/problems/*.mdx
 *   src/generated/manualPapers.ts    — map of content/manual/papers/*.mdx
 *   src/generated/manualPages.ts     — map of content/manual/pages/*.mdx
 *   src/generated/articles.ts        — metadata + import map of content/articles/*.mdx
 */
import { promises as fs } from 'fs';
import path from 'path';
import { createRequire } from 'module';

const require = createRequire(import.meta.url);
const yaml = require('js-yaml');

const baseDir = process.cwd();
const outDir = path.join(baseDir, 'src', 'generated');

async function listMdx(dir) {
  try {
    return (await fs.readdir(dir)).filter((f) => f.endsWith('.mdx'));
  } catch {
    return [];
  }
}

async function generateManualMap(subdir, exportName, outFile) {
  const files = await listMdx(path.join(baseDir, 'content', 'manual', subdir));
  const entries = files.map((file) => {
    const slug = path.basename(file, '.mdx');
    return `  "${slug}": () => import("../../content/manual/${subdir}/${slug}.mdx")`;
  });
  const body =
    `// AUTO-GENERATED by scripts/generate-content-maps.mjs — do not edit.\n` +
    `export const ${exportName} = {\n${entries.join(',\n')}\n} as const;\n`;
  await fs.writeFile(path.join(outDir, outFile), body);
}

function parseFrontmatter(source) {
  const match = /^---\r?\n([\s\S]*?)\r?\n---/.exec(source);
  if (!match) return {};
  try {
    return yaml.load(match[1]) ?? {};
  } catch (err) {
    console.warn('  ! Invalid frontmatter:', err.message);
    return {};
  }
}

async function generateArticles() {
  const dir = path.join(baseDir, 'content', 'articles');
  const files = await listMdx(dir);
  const metas = [];
  const imports = [];
  for (const file of files) {
    const slug = path.basename(file, '.mdx');
    const source = await fs.readFile(path.join(dir, file), 'utf8');
    const fm = parseFrontmatter(source);
    if (!fm.title) {
      console.warn(`  ! content/articles/${file} has no "title" in frontmatter — skipped.`);
      continue;
    }
    metas.push({
      slug,
      title: String(fm.title),
      description: fm.description ? String(fm.description) : '',
      date: fm.date ? String(fm.date) : '',
      updated: fm.updated ? String(fm.updated) : undefined,
      tags: Array.isArray(fm.tags) ? fm.tags.map(String) : [],
      status: fm.status === 'draft' ? 'draft' : 'published',
    });
    imports.push(`  "${slug}": () => import("../../content/articles/${slug}.mdx")`);
  }

  const body = `// AUTO-GENERATED by scripts/generate-content-maps.mjs — do not edit.
export interface ArticleMeta {
  slug: string;
  title: string;
  description: string;
  date: string;
  updated?: string;
  tags: string[];
  status: 'published' | 'draft';
}

export const articleMetas: ArticleMeta[] = ${JSON.stringify(metas, null, 2)};

export const articleImports = {
${imports.join(',\n')}
} as const;
`;
  await fs.writeFile(path.join(outDir, 'articles.ts'), body);
}

