/**
 * MONOGRAPH WEB EDITION (content/monograph/*.mdx)
 *
 * Each file is one chapter, appendix, or the bibliography of the Version 1.0
 * monograph. Frontmatter carries kind/number/label/part/order. This scanner
 * additionally extracts the numbered section list (## headings + the explicit
 * <a id> anchors the converter placed before them) and simple content stats,
 * so the hub page, chapter contents boxes, sitemap, llms.txt, graph.json and
 * /monograph/manifest.json all derive from the actual shipped text.
 */
async function generateMonograph() {
  const dir = path.join(baseDir, 'content', 'monograph');
  const files = await listMdx(dir);
  const metas = [];
  const imports = [];
  for (const file of files) {
    const slug = path.basename(file, '.mdx');
    const source = await fs.readFile(path.join(dir, file), 'utf8');
    const fm = parseFrontmatter(source);
    if (!fm.title || fm.order === undefined) {
      console.warn(`  ! content/monograph/${file} missing title/order — skipped.`);
      continue;
    }
    // numbered sections: <a id="anchor"></a> immediately before "## N.M Title"
    const sections = [];
    const secRe = /<a id="([^"]+)"><\/a>\s*\n+## ([0-9AB]+(?:\.[0-9]+)+|[0-9]+\.[0-9]+) (.+)/g;
    let m;
    while ((m = secRe.exec(source)) !== null) {
      sections.push({ anchor: m[1], number: m[2], title: m[3].trim() });
    }
    // stats from the shipped text
    const displayEquations = (source.match(/^\s*\$\$\s*$/gm) || []).length / 2;
    const numberedEquations = (source.match(/\\tag\{[^}]+\}/g) || []).length;
    const tables = (source.match(/^\s*\|[ :]*-/gm) || []).length;
    const bibliographyEntries =
      fm.kind === 'bibliography' ? (source.match(/^\d+\. /gm) || []).length : 0;
    const description = String(fm.description || '')
      .replace(/\$[^$]*\$/g, (s) => s.slice(1, -1).replace(/\\[a-zA-Z]+/g, '').trim())
      .replace(/\s+/g, ' ')
      .trim();
    metas.push({
      slug,
      title: String(fm.title),
      kind: String(fm.kind || 'chapter'),
      number: String(fm.number ?? ''),
      label: String(fm.label || ''),
      part: fm.part === null || fm.part === undefined ? null : Number(fm.part),
      order: Number(fm.order),
      description,
      sections,
      stats: { displayEquations, numberedEquations, tables, bibliographyEntries },
    });
    imports.push(`  "${slug}": () => import("../../content/monograph/${slug}.mdx")`);
  }
  metas.sort((a, b) => a.order - b.order);

  const body = `// AUTO-GENERATED by scripts/generate-content-maps.mjs — do not edit.
export interface MonographSection {
  anchor: string;
  number: string;
  title: string;
}

export interface MonographItemMeta {
  slug: string;
  title: string;
  kind: 'chapter' | 'appendix' | 'bibliography' | string;
  number: string;
  label: string;
  part: number | null;
  order: number;
  description: string;
  sections: MonographSection[];
  stats: {
    displayEquations: number;
    numberedEquations: number;
    tables: number;
    bibliographyEntries: number;
  };
}

export const monographItems: MonographItemMeta[] = ${JSON.stringify(metas, null, 2)};

export const monographImports = {
${imports.join(',\n')}
} as const;
`;
  await fs.writeFile(path.join(outDir, 'monograph.ts'), body);
}

